import React, { useState } from "react";

function DBSCAN() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const runModule5 = async () => {
    setLoading(true);
    setError("");
    setResult(null);

    try {
      const res = await fetch("http://127.0.0.1:5000/module5");

      if (!res.ok) {
        throw new Error("Server not responding");
      }

      const data = await res.json();
      console.log("DBSCAN Response:", data);

      if (data.status === "success") {
        setResult(data);
      } else {
        setError(data.message || "Error from backend");
      }
    } catch (err) {
      console.error(err);
      setError("Backend connection failed");
    }

    setLoading(false);
  };

  return (
    <div style={{ textAlign: "center" }}>
      <h2>Module 5: DBSCAN</h2>

      <button onClick={runModule5}>Run Module 5</button>

      {loading && <p>Processing...</p>}
      {error && <p style={{ color: "red" }}>{error}</p>}

      {result && result.status === "success" && (
        <div>
          <h3>
            F1 Score:{" "}
            {typeof result.f1_score === "number"
              ? (result.f1_score * 100).toFixed(2) + "%"
              : "0.00%"}
          </h3>
        </div>
      )}
    </div>
  );
}

export default DBSCAN;
